import { DetailedHTMLProps, HTMLAttributes, useCallback, useEffect, useState } from "react";


export const Background: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const [showBackground, setShowBackground] = useState(true)

    useEffect(()=>{
        const windowWidth = window.innerWidth;
        if(windowWidth < 750){
            setShowBackground(false)

        }
        const windowWatcher = ()=>{
             const windowWidth = window.innerWidth;
            console.log(windowWidth)
            if(windowWidth < 750){
            setShowBackground(false)
            }
            if(windowWidth > 750){
            setShowBackground(true)
            }
        }
        window.addEventListener('resize', windowWatcher)
        return () => window.removeEventListener('resize', windowWatcher)
    }, [window.innerWidth])
    const image = 'data:image/png;base64,'
    const style = showBackground ? { 
        backgroundImage: `url(${image})`,
        backgroundSize: '100vw 100vh',
        backgroundPosition: 'center',
        width: '100%',
          } : {
            background: 'linear-gradient(90deg,rgba(242, 242, 242, 1) 0%, rgb(195, 240, 222) 93%)'
      
        }

             
    return (
        <div style={{ ...style }}> 
            {children}
        </div>
    );
}